return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'is','pot-creation-date'=>'2026-02-27 15:06-0600','po-revision-date'=>'2026-03-09 08:39-0500','translation-revision-date'=>'2026-03-09 08:39-0500','project-id-version'=>'ICS Calendar','x-generator'=>'Poedit 3.8','messages'=>['%1$s is currently %2$spaused%3$s, and is not serving calendars on front end pages. You can resume serving calendars under the %4$sUtilities%5$s tab %6$shere%7$s.'=>'%1$s er nú %2$sstöðvað%3$s og er ekki að birta dagatöl á forsíðum. Þú getur haldið áfram að birta dagatöl undir %4$sUtilities%5$s flipanum %6$shér%7$s.','%1$sYou are running ICS Calendar in a WordPress Playground implementation.%2$s Because ICS Calendar is intended to run on a web server, some features may be unavailable or may not function properly.'=>'%1$sÞú ert að keyra ICS Calendar í WordPress Playground-uppsetningu.%2$s Þar sem ICS Calendar er ætlað að keyra á vefþjóni geta sumar aðgerðir verið óaðgengilegar eða virkað illa.','%1$sYour site is currently using a UTC offset-based timezone setting.%2$s This can produce time display errors in the %3$s plugin in locations that observe Daylight Saving Time. Please %4$schange your timezone setting%5$s to the city nearest your location, in the same timezone, for proper time display. See our %6$sdocumentation%7$s for additional information on this issue.'=>'%1$sVefsvæðið þitt notar nú tímasetningu byggða á UTC-bili.%2$s Þetta getur valdið villum í tímasýningu í %3$s viðbótinni á stöðum sem fylgja sumartíma. Vinsamlegast %4$sbreyttu tímasetningunni þinni%5$s í borgina sem er næst þér í sama tímabelti til að tryggja rétta tímasýningu. Sjá %6$shandbókina okkar%7$s fyrir frekari upplýsingar um þetta mál.','Important! Your %1$s configuration appears to be exceeding source calendar provider rate limits.'=>'Mikilvægt! Útlit er fyrir að %1$s stilling þín fari yfir hraðamörk frumdagatalveitunnar.','If your calendars are not loading properly, please review your %1$s settings and usage:'=>'Ef dagatölin þín eru ekki að hlaðast rétt, vinsamlegast skoðaðu %1$s stillingar þínar og notkun:','Do not use %1$s in your shortcodes. This feature is intended for troubleshooting only, and should not be left on permanently.'=>'Ekki nota %1$s í stutlkóðum þínum. Þessi aðgerð er ætluð eingöngu til bilanaleitar og ætti ekki að vera virkjuð varanlega.','Increase the %1$s %2$sTransient (cache) expiration%3$s setting to %4$s43200%5$s (12 hours) or greater, to reduce the frequency of requests to the provider. (See note below.)'=>'Hækkaðu %1$s %2$s tímabundna (geymslu) útrunartíma %3$s stillinguna í %4$s43200%5$s (12 klukkustundir) eða hærra, til að draga úr tíðni beiðna til veitanda. (Sjá athugasemd hér að neðan.)','Avoid including a large number of feeds (10 or more) from the same provider in a single %1$s shortcode.'=>'Forðastu að setja marga strauma (10 eða fleiri) frá sama veitanda í einn %1$s stuttkóða.','Temporarily pause ICS Calendar on your front-end pages using the %1$sPause Calendars%2$s utility. (24-48 hours is recommended.)'=>'Stöðvaðu tímabundið ICS-dagatal á forsíðum þínum með %1$sPause Calendars%2$s-verkfærinu. (Mælt er með 24–48 klukkustundum.)','%1$s includes built-in caching, specifically to improve performance and avoid exceeding provider rate limits. Circumventing this caching with a very low %2$sreload%3$s setting may trigger a temporary block on your web server IP address, or possibly on your entire hosting network, by the calendar provider.'=>'%1$s inniheldur innbyggðan skyndiminni, sérstaklega til að bæta afköst og koma í veg fyrir að farið sé fram úr hraðatakmörkunum þjónustuveitunnar. Að sniðganga þetta skyndiminni með mjög lágum %2$sreload%3$s stillingum getur leitt til tímabundinnar lokunar á IP-tölu vefþjónsins þíns, eða hugsanlega á allt hýsingarnetið þitt, af hálfu dagatalveitunnar.','After making the recommended changes, please allow up to 24 hours for your calendar provider to remove any temporary blocks on your IP address. If you find that the problem persists, please use our %1$ssupport request form%2$s to contact us, and be sure to include your %3$ssystem report%4$s.'=>'Eftir að hafa gert ráðlagðar breytingar, vinsamlegast leyfðu allt að 24 klukkustundir til að veitandi dagatalsins þíns fjarlægi tímabundnar blokkir á IP-tölu þína. Ef vandamálið varir, vinsamlegast notaðu %1$sstuðningsbeiðniseyðublað%2$s til að hafa samband við okkur og vertu viss um að fylgja með %3$skerfisskýrslu%4$s.','Note: Set the %1$sTransient (cache) expiration%2$s as large as possible, considering how frequently event information in your calendar is typically updated. %3$s Remember that you can use the %4$sClear Cached Calendar Data%5$s utility to manually clear the cache at any time, if needed.'=>'Athugið: Stillið %1$sTransient (cache) expiration%2$s eins hátt og mögulegt er, með hliðsjón af því hve oft atburðaupplýsingar í dagatalinu ykkar eru venjulega uppfærðar. %3$s Mundu að þú getur notað %4$sClear Cached Calendar Data%5$s til að hreinsa skyndiminnið handvirkt hvenær sem er, ef þörf krefur.','%1$sPlease note:%2$s %3$s version 10.6 changes the default options for several shortcode settings. In order to maintain consistency, these new defaults are %4$snot%5$s enabled when upgrading from an earlier version. If you would like to learn more about the changes please read our %6$sblog post%7$s, or to switch to the new defaults, turn on the %8$s option on the %9$s settings%10$s page.'=>'%1$sVinsamlegast athugið:%2$s %3$s Útgáfa 10.6 breytir sjálfgefnu valkostunum fyrir nokkrar stillingar stuttkóða. Til að tryggja samræmi eru þessir nýju sjálfgefnir valkostir %4$sekki%5$s virkjaðir við uppfærslu úr eldri útgáfu. Ef þú vilt fræðast meira um breytingarnar, lestu %6$sbloggfærsluna%7$s okkar, eða til að skipta yfir í nýju sjálfgefin gildi, kveiktu á %8$s valkostinum á %9$s stillingasíðunni%10$s.','Use new parameter defaults (v.10.6)'=>'Nota nýja sjálfgefna gildi paraметra (v.10.6)','%1$sPlease note:%2$s %3$s version 11.0 streamlines the way ICS feed URLs are retrieved. This change uses a standard built-in WordPress function, so it should be fully compatible with all existing installations. If you encounter any new issues after upgrading to version 11 or later, please visit the %4$sWordPress Support Forums%5$s for assistance.'=>'%1$sVinsamlegast athugið:%2$s %3$s Útgáfa 11.0 einfaldað leiðina til að sækja ICS-fóðurs-URL-slóðir. Þessi breyting notar staðlaða innbyggða WordPress-fall, svo hún ætti að vera fullkomlega samhæfð við allar núverandi uppsetningar. Ef þú rekst á ný vandamál eftir uppfærslu í útgáfu 11 eða nýrri, vinsamlegast heimsæktu %4$sWordPress stuðningsvettvanginn%5$s til að fá aðstoð.','%1$sPlease note:%2$s %3$s version 11.5.14.2 introduces a new, more secure method for handling calendar parameters when loading via AJAX. Please clear any caching plugins you are using, to ensure that your calendars are loading properly with the new method.'=>'%1$s Vinsamlegast athugið:%2$s %3$s Útgáfa 11.5.14.2 kynnir nýja, öruggari aðferð til að meðhöndla dagatalstillingar við hleðslu í gegnum AJAX. Vinsamlegast hreinsið skyndiminni viðbótanna sem þið eruð að nota til að tryggja að dagatalin hlaðast rétt með nýju aðferðinni.','%1$sWelcome to %2$s version 12!%3$s Version 12.0 introduces additional troubleshooting tools, plus a number of performance improvements and interface refinements throughout. Please see the %4$schangelog%5$s for more details on this update.'=>'%1$sVelkomin í %2$s útgáfu 12!%3$s Útgáfa 12.0 kynnir viðbótar bilanaleitartól, auk fjölda frammistöðubóta og viðbóta í notendaviðmóti um allt. Vinsamlegast skoðið %4$sbreytingaskrána%5$s fyrir nánari upplýsingar um þessa uppfærslu.','Getting Started'=>'Byrja hér','Settings'=>'Stillingar','Appearance'=>'Útlit','Utilities'=>'Veitufyrirtæki','System Report'=>'Kerfisskýrsla','Support'=>'Aðstoð','Upgrade to %1$s!'=>'Uppfærðu í %1$s!','Show/hide all'=>'Sýna/fela allt','ICS file could not be retrieved or was empty. Please verify URL is correct, and check your php.ini configuration to verify either cURL or allow_url_fopen is available. If you are using spaces to delimit multiple URLs, you may also wish to try using the pipe character instead. Affected URL:'=>'ICS-skráin var ekki sótt eða var tóm. Vinsamlegast athugaðu að URL-ið sé rétt og kíktu í php.ini-stillingarnar þínar til að ganga úr skugga um að annað hvort cURL eða allow_url_fopen sé tiltækt. Ef þú ert að nota bil til að aðskilja mörg URL gætirðu einnig reynt að nota rörmerkið (|) í staðinn. Hið fyrirhugaða URL:','Hide past events'=>'Fela fyrri atburði','Show past events'=>'Sýna fyrri atburði','Contact:'=>'Hafðu samband:','Resources:'=>'Auðlindir:','Click for more...'=>'Smelltu til að sjá meira...','Save to your calendar'=>'Bæta við dagatalinu þínu','Cancelled'=>'Hætt við','The legacy parser option is deprecated and will be removed in a future update.'=>'Legacy parser-valkosturinn er úreltur og verður fjarlægður í komandi uppfærslu.','Print'=>'Prenta','The "currentweek" shortcode attribute is deprecated. Please use view="week" in your shortcode instead.'=>'Eiginleikinn "currentweek" í shortcode-inum er úreltur. Vinsamlegast notaðu view="week" í staðinn.','The "legendinline" shortcode attribute is deprecated. Please use legendstyle="inline" in your shortcode instead.'=>'Eiginleikinn "legendinline" í shortcode er úreltur. Vinsamlegast notaðu legendstyle="inline" í shortcode-inum þínum í staðinn.','%1$s has %2$sresumed%3$s serving calendars on front end pages. If your site uses a caching plugin, you may need to clear the cache.'=>'%1$s hefur %2$sendurræst%3$s birtingu dagatalanna á forsíðum. Ef vefsvæðið þitt notar skyndiminni-viðbót gætirðu þurft að tæma skyndiminnið.','%1$s has %2$spaused%3$s serving calendars on front end pages. If your site uses a caching plugin, you may need to clear the cache.'=>'%1$s hefur %2$spausað%3$s birtingu dagatalanna á forsíðum. Ef vefsvæðið þitt notar skyndiminni-viðbót gætir þú þurft að tæma skyndiminnisgeymsluna.','Cleared %1$s %2$s transient(s).'=>'Hreinsaði %1$s %2$s tímabundna atburði.','No %1$s transients were found.'=>'Engar %1$s skammtímabreytingar fundust.','All saved ICS feed URLs have been cleared.'=>'Allar vistaðar ICS-vefslóðir hafa verið hreinsaðar.','All %1$s settings have been reset to defaults, and saved ICS feed URLs have been cleared.'=>'Öll %1$s stillingar hafa verið stilltar aftur í upprunalegt ástand og vistaðar ICS-fóðurs-URL-slóðir hafa verið hreinsaðar.','Your feed URL appears to contain HTTP Basic Authentication credentials. Try turning off the %1$s option under the %2$s tab above.'=>'URL-ið fyrir fóðrið virðist innihalda HTTP Basic Authentication-auðkenni. Reyndu að slökkva á %1$s valkostinum undir %2$s flipanum hér að ofan.','Use legacy feed request method'=>'Notaðu gamaldags aðferð til að senda fóðurskipanir','%1$sThis URL points to a file in your Media Library.%2$s While you should be able to use this URL in an %3$s shortcode, it will be a static snapshot of the calendar at the time the file was created, and will not reflect any future updates to the source calendar. Please see our %4$sUser Guide%5$s for instructions on obtaining your correct dynamic feed URL.'=>'%1$sÞessi slóði vísar á skrá í fjölmiðlasafni þínu.%2$s Þó að þú ættir að geta notað þessa slóð í %3$sshortcode, þá er um að ræða kyrrstæða mynd af dagatalinu á þeim tíma sem skráin var búin til, og hún mun ekki endurspegla neinar framtíðaruppfærslur á upprunalegu dagatalinu. Vinsamlegast sjá %4$snotendahandbók%5$s okkar fyrir leiðbeiningar um hvernig þú færð réttu virku fóðurslóðina.','Error: Could not resolve IP address for %1$s.'=>'Villa: Ekki var hægt að leysa IP-tölu fyrir %1$s.','Resolved IP address for %1$s:'=>'Leyst IP-tala fyrir %1$s:','%1$sAppearance updated.%2$s You may need to refresh the page to see some changes.'=>'%1$s Útlitið hefur verið uppfært.%2$s Þú gætir þurft að endurnýja síðuna til að sjá sumar breytingar.','The text entered in the "Default shortcode" field is not a valid shortcode, and was not saved.'=>'Texti sem sleginn var inn í reitinn "Default shortcode" er ekki gilt shortcode og var ekki vistaður.','%1$sSettings updated.%2$s You may need to refresh the page to see some changes.'=>'%1$s Stillingar uppfærðar. %2$s Þú gætir þurft að endurnýja síðuna til að sjá sumar breytingar.','calendar event'=>'dagskrárviðburður','Event download failed.'=>'Niðurhal viðburðar mistókst.','The legacy feed request method is deprecated, and will be removed in an update in the near future. Please test your feeds with the legacy feed request method turned off.'=>'Legacy-aðferðin til að senda fóðurspurningu er úrelt og verður fjarlægð í uppfærslu innan skamms. Vinsamlegast prófið fóðursendingar ykkar með legacy-aðferðinni slökkt.','Future updates of %1$s will require WordPress 5.3 or newer. Please update your site to a newer version of WordPress as soon as possible.'=>'Komandi uppfærslur á %1$s krefjast WordPress 5.3 eða nýrri. Vinsamlegast uppfærðu síðuna þína í nýrri útgáfu af WordPress sem fyrst.','An error occurred with %1$s while attempting to copy language translation files. The required PHP filesystem function %2$s is unavailable. This is required to address a conflict with certain translation customization plugins such as %3$s. As a result, %1$s translations may not load properly while the conflicting translation plugin is active.'=>'Villa kom upp með %1$s þegar reynt var að afrita tungumálstýpingarskrár. Nauðsynleg PHP-skrárkerfisvirkni %2$s er ekki tiltæk. Þetta er nauðsynlegt til að leysa árekstur við ákveðna viðbætur fyrir sérsniðna þýðingu, svo sem %3$s. Af þeim sökum kunna þýðingar %1$s ekki að hlaðast rétt á meðan árekstursvaldandi þýðingarviðbótin er virk.','Map'=>'Kort','Recurring event'=>'Endurtekinn viðburður','Recurs every %1$s years'=>'Endurtekur sig á hverjum %1$s árum','Recurs yearly'=>'Endurtekur sig árlega','Recurs every %1$s months'=>'Endurtekur sig á hverjum %1$s mánuðum','Recurs monthly'=>'Endurtekur sig mánaðarlega','Recurs every %1$s weeks'=>'Endurtekur sig á hverjum %1$s vikum','Recurs weekly'=>'Endurtekur sig vikulega','Recurs every %1$s days'=>'Endurtekur sig á hverjum %1$s dögum','Recurs daily'=>'Endurtekur sig daglega','The "url" property in your %1$s shortcode appears to contain HTML tags; most likely your URL has been turned into a clickable link. Your calendar may not display properly as a result. Please remove the clickable link in the shortcode.'=>'Eiginleikinn "url" í %1$s shortcode-inum þínum virðist innihalda HTML-merki; líklegast hefur URL-ið þitt verið breytt í smellanlegan hlekk. Dagatal þitt gæti ekki birst rétt vegna þess. Vinsamlegast fjarlægðu smellanlega hlekkinn úr shortcode-inum.','The r34ics_url_get_contents() function is no longer supported.'=>'r34ics_url_get_contents() fallið er ekki lengur studd.','Add %1$s'=>'Bæta við %1$s','Close'=>'Loka','ICS Feed URL:'=>'ICS fóðurslota:','Be sure you are using a %1$ssubscribe%2$s URL, not a %3$sweb view%4$s URL.%5$s (Entering the URL directly in your web browser should download an %6$s file.)'=>'Gakktu úr skugga um að þú sért að nota %1$ssubscribe%2$s-URL, ekki %3$sweb view%4$s-URL.%5$s (Ef þú slærð URL-ið beint inn í vafrann þinn ættirðu að hlaða niður %6$s skrá.)','Calendar Title:'=>'Titill dagatalins:','Leave empty to use calendar&rsquo;s default title. Enter %1$s to omit title altogether.'=>'Látið auðið til að nota sjálfgefna titil dagatalsins. Sláðu inn %1$s til að sleppa titlinum alfarið.','Calendar Description:'=>'Lýsing dagatals:','Leave empty to use calendar&rsquo;s default description. Enter %1$s to omit description altogether.'=>'Látið auðugt til að nota sjálfgefna lýsingu dagatalsins. Sláðu inn %1$s til að sleppa lýsingunni alfarið.','View:'=>'Skoða:','month'=>'mánuð','list'=>'listi','week'=>'vikan','Count:'=>'Fjöldi:','Format:'=>'Sniðmát:','Leave %1$s blank to include all upcoming events. %2$s must be a standard %3$sPHP date format string%4$s.'=>'Láttu %1$s tómt til að innifela alla komandi viðburði. %2$s verður að vera staðlaður %3$sPHP dagsetningarformstrengur%4$s.','Show event descriptions %1$s(change to a number in inserted shortcode to set word limit)%2$s'=>'Sýna viðburðalýsingar %1$s(breyttu í tölu í innfelldum stuttkóða til að stilla orðamörk)%2$s','Show event locations %1$s(if available)%2$s'=>'Sýna viðburðastaði %1$s(ef tiltækt)%2$s','Show event organizers %1$s(if available)%2$s'=>'Sýna viðburðastjórnendum %1$s(ef tiltækt)%2$s','%1$sNote:%2$s Additional %3$sdisplay options%4$s are available by manually editing the shortcode after insertion.'=>'%1$sAthugið:%2$s Viðbótar %3$sskjávalkostir%4$s eru í boði með því að breyta stuttkóðanum handvirkt eftir innsetningu.','Insert %1$s'=>'Settu inn %1$s','Do even more with %1$s version 6!'=>'Gerðu enn meira með %1$s útgáfu 6!','Calendar Builder + Block Editor'=>'Dagatalagerandi + Bútaritill','Configure all calendar settings with an easy visual interface, and use the new %1$s block to select your saved calendars from a dropdown in the Block Editor, no shortcode needed! %2$sLearn more...%3$s'=>'Stilla allar dagatalastillingar með einföldu sjónrænu viðmóti og notaðu nýja %1$s-blokkina til að velja vistaða dagatölin þín úr fellivalmynd í blokk ritlinum, enginn shortcode nauðsynlegur! %2$sLærðu meira...%3$s','Additional Views and Enhanced Features'=>'Viðbótarsýnir og bættir eiginleikar','%1$s offers many new ways to display your calendar, including integrations with the popular %2$s and %3$s open source libraries. Month and year views with a sidebar for the selected day. "Up Next" works great for radio or TV station schedules. Widget and year availability are perfect for holiday bookings. Plus, additional capabilities are added to the core Month, Basic, List and Week views. %4$sView sample calendars...%5$s'=>'%1$s býður upp á margar nýjar leiðir til að birta dagatalið þitt, þar á meðal samþættingu við vinsælu %2$s og %3$s opinn hugbúnaðarbókasöfn. Mánaðar- og ársyfirlitssýnir með hliðarstiku fyrir valinn dag. "Næst á dagskrá" hentar frábærlega fyrir dagskrár útivarps- eða sjónvarpsstöðva. Aðgengi viðmóts og árs er fullkomið fyrir bókanir á frídögum. Auk þess eru bætt við aukaaðgerðir inn í kjarnasýnar Mánuður, Grunn, Listi og Vika. %4$sSkoða sýnishorn af dagatölum...%5$s','Customization'=>'Aðlögun','Easy-to-use tools to completely customize your calendar colors, typography and more. Select one of our preset color palettes or create your own, with options to individually customize the color of each element in the calendar layout. Choose between your theme fonts, system fonts, or more than 20 included open source fonts. %1$sLearn more...%2$s'=>'Auðveld verkfæri til að sérsníða liti, leturfræði og fleira í dagatalinu þínu. Veldu eina af fyrirfram stilltum litapallettum okkar eða búaðu til þína eigin, með möguleikum á að sérsníða lit hvers þáttar í dagatalauppsetningunni. Veldu á milli þemaletra, kerfisletra eða yfir 20 innifalinna opins letra. %1$sLærðu meira...%2$s','ICS Events'=>'ICS viðburðir','Turns %1$s into a full calendar management system. Create and edit new events directly in WordPress, and even integrate them seamlessly with your existing external ICS feeds. %2$sLearn more...%3$s'=>'Umbreytir %1$s í fullt dagatalstjórnunarkerfi. Búðu til og breyttu nýjum viðburðum beint í WordPress og samþættðu þá hnökralaust við núverandi ytri ICS-gjafir. %2$sLærðu meira...%3$s','Localized Admin Interface'=>'Staðfært stjórnendaviðmót','All %1$s admin pages are translated into dozens of languages, including English, Czech, Danish, German, Greek, Spanish, Estonian, Finnish, French, Hungarian, Italian, Japanese, Korean, Lithuanian, Latvian, Norwegian, Dutch, Polish, Portuguese, Romanian, Russian, Slovak, Serbian, Swedish, Turkish, Ukrainian, and Chinese.'=>'Allar %1$s stjórnarsíður eru þýddar á tugi tungumála, þar á meðal ensku, tékknesku, dönsku, þýsku, grísku, spænsku, estnesku, finnsku, frönsku, ungversku, ítölsku, japönsku, kóresku, litháísku, lettnesku, norsku, hollensku, pólsku, portúgölsku, rúmensku, rússnesku, slóvakísku, serbnesku, sænsku, tyrknesku, úkraínsku og kínversku.','Visit %1$s to learn more.'=>'Farðu á %1$s til að fá nánari upplýsingar.','Calendar Builder screenshot'=>'Skjámynd af Calendar Builder','Appearance screenshot'=>'Sýnishot af útliti','Available now!'=>'Fáanlegt núna!','Get %1$s!'=>'Fáðu %1$s!','Extensive color palette and typography options are available with %1$s. %2$sLearn More%3$s'=>'Við %1$s er að finna víðtæka litaspala og leturgerðarvalkosti. %2$sLærðu meira%3$s','Color Palette'=>'Litapalleta','Match calendar color palette to current Block Theme colors'=>'Samræma litapallettu dagatalsins við núverandi litir blokkþemans.','beta'=>'beta','Replaces the %1$s default neutral color palette with nearest matches from the current Site Editor Styles color palette or the %2$s file in your theme. Color selections are algorithmic, and some combinations may not pass accessibility contrast tests. This setting has no effect if you are using a "classic" theme that does not include a %3$s file.'=>'Skiptir út sjálfgefnu hlutlausu litapallettunni %1$s fyrir næstu samsvarandi liti úr litapallettu núverandi Site Editor Styles eða úr %2$s skránni í þemanu þínu. Litaúrvalið er reikniritbundið og sumar samsetningar kunna að standast ekki aðgengileika- og kontrastprófanir. Þessi stilling hefur engin áhrif ef þú ert að nota "classic" þema sem inniheldur ekki %3$s skrá.','%1$sThis is currently a beta feature.%2$s It may require making some adjustments to your calendar appearance or CSS for optimal display, especially if you have color-coded your feeds. Functionality is subject to change.'=>'%1$sÞetta er nú beta-eiginleiki.%2$s Það gæti krafist nokkurra breytinga á útliti dagatalsins þíns eða CSS til að tryggja sem besta birtingu, sérstaklega ef þú hefur litað strauma þína. Virkni getur breyst.','Dark mode'=>'Dimmur hamur','Inverts color palette (light colors on a dark background).'=>'Vendir litapallettu (ljósir litir á dökkum bakgrunni).','Save Changes'=>'Vista breytingar','Thank you for installing %1$s. Before creating your first calendar shortcode, please visit your %2$sGeneral Settings%3$s page and verify that your site language, timezone and date/time format settings are correct. See our %4$sUser Guide%5$s for more information.'=>'Þakka þér fyrir að setja upp %1$s. Áður en þú býrð til fyrsta dagatalaskammkóðann þinn, vinsamlegast farðu á síðuna %2$sAlmenn stillingar%3$s og staðfestu að tungumál vefsins, tímabelti og dagsetningar-/tímaformi séu rétt stillt. Sjá %4$sNotendahandbók%5$s okkar fyrir frekari upplýsingar.','Get started with %1$s in four easy steps... and you\'ve already completed step one! Check out our %2$sQuick Start Guide%3$s for the rest.'=>'Byrjaðu með %1$s í fjórum einföldum skrefum... og þú hefur þegar lokið fyrsta skrefinu! Skoðaðu %2$shröðarleiðbeininguna okkar%3$s fyrir restina.','Quick Start Guide'=>'Fljótleg upphafsleiðbeining','An extensive %1$sUser Guide%2$s is available on our website. Below are some quick links to key resources in the documentation.'=>'Viðamikill %1$snotendahandbók%2$s er aðgengileg á vefsíðu okkar. Hér að neðan eru nokkrar skjótar tenglar á lykilauðlindir í skjölunum.','General:'=>'Almennt:','General WordPress Settings'=>'Almenn WordPress-stillingar','%1$s Settings'=>'%1$s Stillingar','Working with Shortcodes:'=>'Vinna með stuttkóða:','Shortcode Overview'=>'Yfirlit yfir stuttkóða','Shortcode Builder'=>'Stuttkóða smiður','Shortcode Parameters Reference'=>'Tilvísun í stuttkóða-breytur','Advanced Topics:'=>'Framþróunarefni:','FAQs and Tips'=>'Algengar spurningar og ráð','CSS Guide'=>'Leiðarvísir um CSS','Developer Resources'=>'Úrræði fyrir forritara','GDPR'=>'Persónuverndarreglugerð ESB','Loading'=>'Er að hlaðast','Always use AJAX to render calendars'=>'Notaðu alltaf AJAX til að birta dagatöl.','AJAX loading is now automatic. You can override AJAX, if necessary, by adding %1$s to your shortcode.'=>'AJAX-hleðsla er nú sjálfvirk. Þú getur ógilt AJAX, ef þörf krefur, með því að bæta %1$s við stuttkóðann þinn.','Increase memory limit when rendering calendars'=>'Auka minnismörk við birtingu dagatalanna','If your calendar is failing to load with an "out of memory" fatal error, try increasing the memory limit. A minimum of 512 MB is recommended. %1$s Notes: 1) Some hosting providers may not allow applications to override the server default setting. 2) It is not possible to set this option lower than the current default memory limit on your server.'=>'Ef dagatalinu mistekst að hlaða vegna banvænnar villu "out of memory", reyndu að hækka minnismörkin. Mælt er með að minnsta kosti 512 MB. %1$s Athugasemdir: 1) Sumir hýsingaraðilar kunna að banna forritum að breyta sjálfgefinni stillingu netþjónsins. 2) Ekki er hægt að stilla þennan valkost lægra en núverandi sjálfgefna minnismörk á netþjóninum þínum.','deprecated'=>'Úrelt','Some servers may not support the default feed request method. If your feeds are not loading, turn on this option to use the legacy request method. This feature is deprecated and will be removed in a future update.'=>'Sumir netþjónar kunna að styðja ekki sjálfgefna aðferð til að biðja um strauma. Ef straumarnir þínir hlaðast ekki, kveiktu á þessum valkosti til að nota hina gamalætu beiðnaðaraðferð. Þessi eiginleiki er úreltur og verður fjarlægður í komandi uppfærslu.','Default shortcode'=>'Skýrmerki sjálfgefið','If your site will include a large number of similarly configured calendar shortcodes, you can enter a default "base" shortcode here with the parameters that should be the same for all of the calendars. Individual shortcodes on the site can then include only the parameters that are unique to that calendar, as such: %1$s Any parameters included in the individual shortcode will override what is set here.'=>'Ef vefsvæðið þitt mun innihalda marga stuttkóða fyrir dagatal með svipaðri uppsetningu, geturðu hér slegið inn sjálfgefinn "grunn" stuttkóða með þeim breytum sem eiga að vera eins fyrir öll dagatölin. Einstaka stuttkóðar á vefsvæðinu geta síðan aðeins innihaldið þær breytur sem eru sértækar fyrir viðkomandi dagatal, svona: %1$s Allar breytur sem tilgreindar eru í einstaka stuttkóðanum ganga framar þeim sem hér eru stilltar.','Allow access to these hostnames that resolve to reserved IP addresses'=>'Leyfa aðgang að þessum gestanöfnum sem leysast í varin IP-tölur','If your calendar server is hosted on the same physical server as your website, is part of the same local network, or otherwise uses a %1$sreserved IP address%2$s, enter its hostname here to allow access. For multiple calendar servers, enter one hostname per line. See %3$sthe %4$s documentation%5$s for more information.'=>'Ef dagatalþjónninn þinn er hýstur á sama líkamlega netþjóni og vefsvæðið þitt, er hluti af sama staðarneti eða notar á annan hátt %1$svarinn IP-tölu%2$s, sláðu hér inn gestanavnið hans til að heimila aðgang. Fyrir marga dagatalþjóna skaltu slá inn eitt gestanavn á hverri línu. Sjá %3$s %4$s skjölin%5$s fyrir frekari upplýsingar.','Enter one hostname per line. Hostnames are the base domain name, not a full URL. %1$s For example, you would enter %2$s, not %3$s.'=>'Sláðu inn eitt gestanavn á hverri línu. Gestanöfn eru grunnlénið, ekki heill vefslóðar. %1$s Til dæmis myndirðu slá inn %2$s, ekki %3$s.','Allow access to these ports'=>'Leyfa aðgang að þessum höfnum','WordPress automatically allows access to ports 80, 443, and 8080. If you need to be able to access source calendars that use non-standard ports, enter the port numbers here, separated by commas.'=>'WordPress leyfir sjálfkrafa aðgang að höfnum 80, 443 og 8080. Ef þú þarft að hafa aðgang að upprunalegum dagatölum sem nota óstaðlaðar hafnir, sláðu inn höfnunarnúmerin hér, aðskilin með kommum.','Caching'=>'Í skyndiminni','Transient (cache) expiration'=>'Útlimun tímabundinnar skyndiminni','seconds'=>'sekúndur','Sets how long calendar feed data should be cached on the server (WordPress transients) before reloading. Default is 3600 (1 hour). Minimum allowed value is 120 (2 minutes).'=>'Stýrir hversu lengi dagatal-fóðursgögn skuli vera í skyndiminni á netþjóninum (WordPress transients) áður en þau eru hlaðin inn aftur. Sjálfgefið gildi er 3600 (1 klst). Lágmarksleyfilegt gildi er 120 (2 mín).','Admin'=>'Admin','Minimum access role'=>'Lágmarksaðgangshlutverk','Identifies the minimum user role that is allowed to access %1$s admin pages. Certain areas such as Settings are further restricted to %2$s users only (%3$s users on Multisite configurations).'=>'Gefur til kynna lágmarksnotendahlutverk sem hefur heimild til aðgangs að %1$s stjórnendasíðum. Ákveðin svæði, svo sem Stillingar, eru enn frekar takmörkuð við %2$s notendur eingöngu (%3$s notendur í Multisite-uppsetningum).','Register Customizer'=>'Skráðu sérsniðningaraðila','WordPress no longer includes a link to the Customizer in the Appearance menu when a Block Theme is active. Check this box if you wish to use the Customizer, e.g. for the Additional CSS input. Note: Some themes or plugins may already register the Customizer, in which case, this setting will have no effect. (The checkbox only enables the Customizer when checked; it does not disable the Customizer when unchecked.)'=>'WordPress inniheldur ekki lengur hlekk á sérsniðningartólið í Útlitsvalmyndinni þegar blokkþema er virkt.  Merktu við þetta reit ef þú vilt nota sérsniðningartólið, t.d. fyrir viðbótar CSS-innslátt.  Athugið: Sum þemu eða viðbætur kunna þegar að hafa skráð sérsniðningartólið, og þá mun þessi stilling ekki hafa áhrif. (Reiturinn virkjar sérsniðningartólið þegar hann er merktur; hann óvirkjar það ekki þegar hann er ómerktur.)','Remove "Add ICS Calendar" button in Classic Editor'=>'Fjarlægja hnappinn "Bæta við ICS-dagatali" í klassíska ritlinum','By default, ICS Calendar adds an "Add ICS Calendar" button to the toolbar above the WYSIWYG editor when using Classic Editor. Check this box to remove the button. Has no effect on sites using the Block Editor (Gutenberg).'=>'Á sjálfgefinni stillingu bætir ICS Calendar við hnappinn "Bæta við ICS-dagatali" í verkfærastikuna fyrir ofan WYSIWYG-ritilinn þegar Classic Editor er notaður. Merktu við þennan reit til að fjarlægja hnappinn. Á engin áhrif á vefsíður sem nota Block Editor (Gutenberg).','%1$s version 10.6 introduced new default values for several shortcode parameters. New installations automatically use the new default values, but upgraded installations will continue to use the old default values, unless this box is checked. Read more about these changes on %2$sour blog%3$s.'=>'%1$s Útgáfa 10.6 kynnti ný sjálfgefin gildi fyrir nokkra stuttkóða-breytur. Nýjar uppsetningar nota sjálfgefin gildi sjálfkrafa, en uppfærðar uppsetningar munu áfram nota gömlu sjálfgefin gildin, nema þetta reitinn sé hakað. Lestu meira um þessar breytingar á %2$sbloggi okkar%3$s.','User Guide'=>'Notendahandbók','Our complete user guide is available with full translation into dozens of languages on our website:'=>'Heildar notendahandbókin okkar er fáanleg með fullri þýðingu á tugi tungumála á vefsíðunni okkar:','For assistance, please use our %1$ssupport request form%2$s.'=>'Fyrir aðstoð, vinsamlegast notaðu %1$sstuðningsbeiðniseyðublað%2$s okkar.','When contacting support, please include the %1$ssystem report%2$s from this page.'=>'Þegar haft er samband við þjónustuverið, vinsamlegast fylgið %1$skerfisskýrslu%2$s af þessari síðu.','Spread the word!'=>'Spread the word!','If you find %1$s useful, you can help support our continued growth and development with a %2$sfive-star review%3$s. Thank you!'=>'Ef þú finnur %1$s gagnlegt, geturðu stutt við áframhaldandi vöxt og þróun okkar með %2$sfimm stjörnu umsögn%3$s. Takk fyrir!','Calendar Status: %1$sPaused%2$s'=>'Staða dagatals: %1$sStöðvað%2$s','Calendar Status: %1$sActive%2$s'=>'Staða dagatals: %1$sVirkt%2$s','Use the pause button if you need to temporarily turn off %1$s on your front end pages.'=>'Notaðu hléhnappinn ef þú þarft að slökkva tímabundið á %1$s á forsíðum forenda þíns.','Resume Calendars'=>'Halda áfram dagatal','Pause Calendars'=>'Stöðva dagatal','No content will be altered, but your calendars will be hidden and no %1$s asset files (JavaScript, CSS) will be loaded on front-end pages. If you are using caching via a plugin or through your hosting provider, you may need to clear the cache after changing this setting.'=>'Enginn efni verður breytt, en dagatölin þín verða falin og engar %1$s auðlínaskrár (JavaScript, CSS) verða hlaðnar á framenda síðum. Ef þú notar skyndiminni í gegnum viðbót eða hjá hýsingaraðila þínum gætir þú þurft að tæma skyndiminnisinn eftir að hafa breytt þessari stillingu.','%1$s Data Cache'=>'%1$s Gagnakass','This will immediately clear all existing cached calendar data (purge transients), forcing WordPress to reload all calendars the next time they are viewed. Caching will then resume as before.'=>'Þetta mun strax hreinsa öll núverandi skyndiminni dagatalgagna (hreinsa tímabundnar skrár), sem neyðir WordPress til að hlaða öllum dagatalum aftur næst þegar þau eru skoðuð. Skyndiminni mun síðan halda áfram eins og áður.','Clear Cached Calendar Data'=>'Hreinsa skyndiminni dagatalgagna','If you are using a third-party caching plugin, you may need to clear your site-wide cache after running this utility.'=>'Ef þú notar skyndiminnisviðbót frá þriðja aðila gætir þú þurft að tæma skyndiminnið fyrir alla síðuna eftir að hafa keyrt þessa gagnsemi.','Are you sure? This will reset all %1$s settings to their defaults. Your saved calendar configurations and shortcodes will be retained, but resetting the defaults may change the appearance of your calendars. If you are using a third-party caching plugin, you may need to clear your site-wide cache after running this utility.'=>'Ertu viss? Þetta mun endurstilla allar %1$s stillingar í upprunalegt ástand. Vistaðar dagatalstillingar þínar og stuttkóðar verða áfram varðveittar, en endurstilling upprunalegra gilda getur breytt útliti dagatalanna. Ef þú notar skyndiminni-viðbót frá þriðja aðila gætir þú þurft að tæma skyndiminnið fyrir alla síðuna eftir að hafa keyrt þennan verkfæri.','Only clear transients (default)'=>'Aðeins skýr hljóðbyltingar (sjálfgefið)','Also clear all saved ICS feed URLs'=>'Einnig hreinsa allar vistaðar ICS-fóðurtenglar.','Reset %1$sall%2$s %3$s settings (including transients and feed URLs)'=>'Endurstilla %1$sallar%2$s %3$s stillingar (þ.m.t. skammvinnar truflanir og fóðurslóðir)','Last cleared:'=>'Síðast hreinsað:','never'=>'aldrei','ICS Feed URL Tester'=>'ICS fóðurslóðarprófari','If you are concerned that the plugin is not properly retrieving your feed, you can test the URL here.'=>'Ef þú hefur áhyggjur af því að viðbótin sé ekki að sækja fóðrið þitt rétt, geturðu prófað vefslóðina hér.','Enter feed URL...'=>'Sláðu inn fóðurslóð...','Test URL'=>'Prófunar-URL','Results:'=>'Niðurstöður:','%1$s received.'=>'%1$s móttekið.','This appears to be a valid ICS feed URL.'=>'Þetta virðist vera gild ICS-fóður-URL.','unknown'=>'óþekkt','This does not appear to be a valid ICS feed URL.'=>'Þetta virðist ekki vera gild ICS-fóðurs-URL.','Could not retrieve data from the requested URL.'=>'Ekki var hægt að sækja gögn úr beiðsluslóðinni.','An unknown error occurred while attempting to retrieve the requested URL.'=>'Óþekkt villa kom upp við tilraun til að sækja beiðnu vefslóðina.','Please copy the following text and include it in your message when emailing support.'=>'Vinsamlegast afritið eftirfarandi texta og setjið hann inn í tölvupóstinn ykkar þegar þið sendið póst til þjónustudeildarinnar.','Also please include the %1$s shortcode exactly as you have it entered on the affected page.'=>'Einnig vinsamlegast taktu %1$s shortcode nákvæmlega eins og þú hefur hann skráðan á viðkomandi síðu.','No events found.'=>'Engin atburðir fundust.','Previous Page'=>'Fyrri síða','Next Page'=>'Næsta síða','All Day'=>'Allan daginn','Previous Month'=>'Fyrri mánuður','Next Month'=>'Næsti mánuður','Today'=>'Í dag','Month selection'=>'Mánaðarval','No events.'=>'Engir viðburðir.','No additional events this month.'=>'Engir viðburðir í viðbót þennan mánuð.','Week selection'=>'Vikuvalið','Last week'=>'Í síðustu viku','This week'=>'Þessa vikuna','Next week'=>'Næstu viku','ICS Calendar'=>'ICS dagatal','https://icscalendar.com'=>'https://icscalendar.com','Turn your Google Calendar, Microsoft Office 365 or Apple iCloud Calendar into a seamlessly integrated, auto-updating, zero-maintenance WordPress experience.'=>'Umbreyttu Google-dagatalinu þínu, Microsoft Office 365-dagatalinu eða Apple iCloud-dagatalinu í hnökralausa, sjálfvirka uppfærsluaðgerð í WordPress án viðhalds.','Room 34 Creative Services, LLC'=>'Herbergi 34 Skapandi þjónusta, LLC']];
